VALUES
  ('social-worker-moex-05040', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '珍妮想要找居家托育服務人員來照顧她的小孩，有人推薦給她以下四位居家托育服務人員，均自 稱有向所在地的居家托育服務中心辦理登記，下列何者不可能符合居家托育服務人員資格？', '["小歐，女性，今年從一般高中畢業，18歲，自稱非常喜歡兒童", "文文，女性，今年56歲，某私立高中家政科畢業", "小張，男性，今年42歲，有修完托育人員專業訓練課程，且有結業證書", "阿力，男性，今年28歲，有保母人員技術士證"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05041', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '對於愛力克森（Erik Erikson）的心理社會發展階段的批評，下列何者正確？', '["反應出當代主流文化的偏見", "歧視女性", "不重視老年人的生產力", "對於兒童期的描述過多，不夠客觀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05042', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '校園霸凌是目前全球兒童及青少年面臨的問題之一，且對兒童及青少年的身心發展影響甚鉅。對 校園霸凌的相關描述，下列何者錯誤？', '["網路霸凌因為具有匿名、立即、多元與持久，傷害程度可能會高於面對面的霸凌", "霸凌事件中常有霸凌者、被霸凌者和旁觀者三種角色，通常這三個角色的劃分是固定不變的", "依據「校園霸凌防制準則」，學校在處理霸凌事件時，若遭遇情節嚴重時，應請求警政、社政 或檢察機關協助", "依據「校園霸凌防制準則」，疑似校園霸凌的被霸凌人或其法定代理人可以向行為人發生行為 時所屬學校提出申請調查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05043', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者是描述「三明治世代」？', '["是指要照顧上一代進入老年期的父母，以及下一代可能在兒童或青春期的孩子的中年期", "是指夾在同儕與家人期待衝突的青少年期", "是指剛自大學畢業進入職場，面對理想與現實兩難的成年初期", "是指面對要尊重子女輩的教養期待與想要疼愛孫子輩又怕違反子女的教養規則的老年期"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05044', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在道德發展的理論中，常見的有Piaget、Kohlberg、Gilligan三位學者。對這三位學者的理論主張 敘述，下列何者錯誤？', '["Piaget將道德發展分為他律和自律兩個階段", "Kohlberg的道德發展以「正義」為取向，Gilligan的道德發展則以「關懷」為取向", "Kohlberg的理論被批判有性別偏見", "Kohlberg的理論係以Freud的心理動力理論為基礎"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05045', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '小元寶為9個月大的嬰兒，如果就Piaget的認知發展理論來說，他屬於感覺動作期的階段，請問 他應該不具有下列那個特質？', '["物體恆存的概念，例如手上玩具掉了，會想要去找", "有簡單的數量概念，例如知道媽媽有3個糖果，自己得到1個，還有2個", "能有初步的方向與目的，例如知道媽媽在自己的右邊，會往那個方向接近", "限於現在的時空知覺，例如無法知道明天要去那裡，或想像自己可能在非現在所處的環境中"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05046', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '花媽想為身心失能已經三年的花婆婆尋找合適的長期照顧服務，請問依據106年6月3日開始施 行的「長期照顧服務法」，下列敘述何者錯誤？', '["居家式的長照服務可以到花婆婆家提供服務，服務項目包含家事服務", "社區式的長照服務是由社區機構派人到花婆婆家提供服務，所以服務項目不包含交通接送", "機構住宿式的長照服務可以讓花婆婆長期入住在機構裡，提供全時的照顧，如果花婆婆有緊急 醫療需求時，也會協助送醫", "如果花媽決定自己在家來照顧花婆婆，他可以申請家庭照顧者的支持服務，像是喘息服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05047', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '幼兒的情緒管理需要成年人的支持與引導、協助，下列那一項不是情感訓練過程中合適的作法？', '["注意幼兒情感變化", "想辦法來直接滿足孩子的各種要求，避免他有負向情緒表現", "了解幼兒的情感是一個提供親密與教育的機會", "同理幼兒的感覺，並幫助孩子描述自己的感覺"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05048', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '2016 年通過「病人自主權利法」後，可以進行預立醫療自主計畫。小方對這項計畫有所好奇， 請教了醫院的醫護人員。請問下列敘述那一樣是錯誤的？', '["年滿20歲、具有行為能力的成年人都可以簽署", "內容包含你對急救意願表達、維生醫療抉擇、預立醫療委任代理人、預立醫囑", "所簽署的文件生效，要在兩位專科醫師判斷生命到末期且你已經無法表達意願時", "一旦簽署後，不論當時的醫療技術是否可以治療，都會放棄醫療救治"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05049', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '愛情是不少人嚮往的情感。若以 Sternberg 的愛情三角理論來看，一個比較完整的愛情需要具備 那些元素？', '["孤獨、親密、承諾", "孤獨、自信、婚姻", "親密、承諾、婚姻", "親密、激情、承諾"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:29+00:00", "source_pdf_sha1": "72531ff92f90", "answer_pdf_sha1": "fbf916b39630", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
